// ── AMAZON AFFILIATE ──────────────────────────────────────────────────────────
// 🔑 Replace with your affiliate tag when ready: e.g. "litsense-20"
const AMAZON_TAG = "litsense-20";

function amazonLink(title, author, isbn) {
  if (isbn && isbn.length >= 10) {
    return `https://www.amazon.com/dp/${isbn}?tag=${AMAZON_TAG}&linkCode=ll1`;
  }
  const q = encodeURIComponent(`${title} ${author}`);
  return `https://www.amazon.com/s?k=${q}&tag=${AMAZON_TAG}`;
}

// ── REVIEW BADGE TIERS ───────────────────────────────────────────────────────
const REVIEW_BADGES = [
  { min:1,  label:"Reviewer",   emoji:"📖", desc:"Wrote your first review" },
  { min:3,  label:"Critic",     emoji:"✍️",  desc:"3 reviews — your voice shapes what others read" },
  { min:5,  label:"Luminary",   emoji:"⭐", desc:"5 reviews — you're a literary force" },
  { min:10, label:"Chronicler", emoji:"🏆", desc:"10 reviews — legendary reader status" },
];
function getReviewBadge(count) {
  for (let i = REVIEW_BADGES.length - 1; i >= 0; i--) {
    if (count >= REVIEW_BADGES[i].min) return REVIEW_BADGES[i];
  }
  return null;
}
function getNextReviewBadge(count) {
  return REVIEW_BADGES.find(b => b.min > count) || null;
}

// ── GENRE EXPANSION BRIDGES ──────────────────────────────────────────────────
// When a user has read deeply in one genre, suggest a bridge genre they may love
const GENRE_BRIDGES = {
  "Literary Fiction": { target:"Historical",    hook:"Readers who love literary fiction almost always fall for great historical fiction too — same prose attention, completely different era." },
  "Thriller":         { target:"True Crime",     hook:"You love the tension of a thriller. True crime gives you that same pull, except it actually happened." },
  "Sci-Fi":           { target:"Philosophy",     hook:"The best sci-fi is philosophy wearing a spacesuit. Have you ever just read the philosophy directly?" },
  "Historical":       { target:"Biography",      hook:"You already love living inside other time periods. A great biography puts you inside someone's actual life." },
  "Romance":          { target:"Literary Fiction",hook:"The best romance novels are literary fiction that doesn't apologize for its emotions." },
  "Psychology":       { target:"Business",       hook:"Behavioral psychology and business strategy are closer than most people realize." },
  "Mystery":          { target:"Thriller",       hook:"Mystery readers who try literary thrillers rarely go back. Same puzzle instinct, higher stakes." },
  "Biography":        { target:"Essays",         hook:"Great biographies and great essay collections are the same thing — one clear voice, one extraordinary mind." },
  "Fantasy":          { target:"Sci-Fi",         hook:"Fantasy readers who cross to sci-fi often find it scratches a different, equally satisfying itch." },
  "Business":         { target:"Biography",      hook:"The best business books are just the biographies of people who built things. Why not read the actual story?" },
};

function getGenreExpansionSuggestion(readBooks, savedBooks, dismissed = []) {
  const all = [...readBooks, ...savedBooks];
  if (all.length < 3) return null;
  const counts = {};
  for (const b of all) {
    const BOOK_TAGS = { "Pachinko":["Literary Fiction"], "A Gentleman in Moscow":["Literary Fiction"], "The Martian":["Sci-Fi"], "Project Hail Mary":["Sci-Fi"] };
    const tags = b.tags || BOOK_TAGS[b.title] || [];
    for (const t of tags) counts[t] = (counts[t]||0) + 1;
  }
  const dominant = Object.entries(counts).sort((a,b)=>b[1]-a[1])[0];
  if (!dominant || dominant[1] < 2) return null;
  const [genre] = dominant;
  const bridge = GENRE_BRIDGES[genre];
  if (!bridge || dismissed.includes(bridge.target)) return null;
  return { fromGenre: genre, toGenre: bridge.target, hook: bridge.hook };
}

