// Load discussions from localStorage, merged with seeds
function loadDiscussions(bookId) {
  const seeds = SEED_DISCUSSIONS[bookId] || [];
  try {
    const stored = JSON.parse(localStorage.getItem(`ls_disc_${bookId}`) || "[]");
    return [...seeds, ...stored].sort((a,b) => b.ts - a.ts);
  } catch { return seeds; }
}

function saveComment(bookId, comment) {
  try {
    const stored = JSON.parse(localStorage.getItem(`ls_disc_${bookId}`) || "[]");
    stored.unshift(comment);
    localStorage.setItem(`ls_disc_${bookId}`, JSON.stringify(stored));
  } catch {}
}

function getCommentCount(bookId) {
  const seeds = (SEED_DISCUSSIONS[bookId] || []).length;
  try {
    const stored = JSON.parse(localStorage.getItem(`ls_disc_${bookId}`) || "[]");
    return seeds + stored.length;
  } catch { return seeds; }
}

function timeAgo(ts) {
  const diff = Date.now() - ts;
  const m = Math.floor(diff / 60000);
  const h = Math.floor(diff / 3600000);
  const d = Math.floor(diff / 86400000);
  if (m < 2)  return "just now";
  if (m < 60) return `${m}m ago`;
  if (h < 24) return `${h}h ago`;
  if (d < 7)  return `${d}d ago`;
  return `${d}d ago`;
}

// ── BOOK SWAP SYSTEM ──────────────────────────────────────────────────────────
// Phase 1: seller posts a listing in the discussion thread.
// Buyer taps "Claim It" — opens a contact card with seller info.
// No payments yet — just a warm introduction. Payment rails come in Phase 2.
//
// Production: listings should live in Supabase with status tracking.
// For now: localStorage per book, merged into the discussion thread.

const BOOK_CONDITIONS = [
  { id:"like-new",  label:"Like New",   emoji:"✨", desc:"Read once, no marks" },
  { id:"very-good", label:"Very Good",  emoji:"👍", desc:"Minor wear, clean pages" },
  { id:"good",      label:"Good",       emoji:"📖", desc:"Well loved, all pages intact" },
];

function loadListings(bookId) {
  try { return JSON.parse(localStorage.getItem(`ls_swap_${bookId}`) || "[]"); } catch { return []; }
}

function saveListing(bookId, listing) {
  try {
    const all = loadListings(bookId);
    // One active listing per seller per book
    const filtered = all.filter(l => l.sellerId !== listing.sellerId);
    filtered.unshift(listing);
    localStorage.setItem(`ls_swap_${bookId}`, JSON.stringify(filtered));
  } catch {}
}

function claimListing(bookId, listingId) {
  try {
    const all = loadListings(bookId);
    const updated = all.map(l => l.id === listingId ? { ...l, claimed: true } : l);
    localStorage.setItem(`ls_swap_${bookId}`, JSON.stringify(updated));
  } catch {}
}

function getActiveListings(bookId) {
  return loadListings(bookId).filter(l => !l.claimed);
}


